### Game Systems Module (NEW)

```rust
// src/systems.rs (NEW FILE)

use rand::Rng;
use crate::types::{DiceSides, ExplosionChain};

/// Maximum explosion depth to prevent infinite loops (D3 from #12)
const MAX_EXPLOSIONS: usize = 10;

/// Roll a single standard die with optional explosion
/// Returns ExplosionChain if exploding, otherwise chain with single value
pub fn roll_standard<R: Rng>(
    rng: &mut R,
    sides: u32,
    exploding: bool,
) -> ExplosionChain {
    let mut values = Vec::new();
    let mut current = rng.gen_range(1..=sides as i32);
    values.push(current);

    if exploding {
        let max = sides as i32;
        let mut explosions = 0;
        while current == max && explosions < MAX_EXPLOSIONS {
            current = rng.gen_range(1..=sides as i32);
            values.push(current);
            explosions += 1;
        }
    }

    ExplosionChain {
        total: values.iter().sum(),
        values,
    }
}

/// Roll a single Fate die: returns -1, 0, or +1
pub fn roll_fate<R: Rng>(rng: &mut R) -> i32 {
    rng.gen_range(-1..=1)
}

/// Map Fate total to ladder name (D2 from #12)
pub fn fate_ladder(total: i32) -> &'static str {
    match total {
        i if i <= -2 => "Terrible",
        -1 => "Poor",
        0 => "Mediocre",
        1 => "Average",
        2 => "Fair",
        3 => "Good",
        4 => "Great",
        5 => "Superb",
        6 => "Fantastic",
        7 => "Epic",
        _ => "Legendary",
    }
}
```

### Engine Extensions (Story 2)

```rust
// src/engine.rs - EXTEND existing roll() method

impl DiceEngine {
    /// Extended roll() to handle Fate dice and explosions
    pub fn roll(&mut self, expr: &DiceExpression) -> Result<RollResult, DiceError> {
        let mut rolls = Vec::new();
        let mut explosions = Vec::new();

        match &expr.sides {
            DiceSides::Standard(sides) => {
                for _ in 0..expr.count {
                    let chain = systems::roll_standard(&mut self.rng, *sides, expr.exploding);
                    rolls.push(chain.total);
                    if expr.exploding && chain.values.len() > 1 {
                        explosions.push(chain);
                    }
                }
            }
            DiceSides::Fate => {
                for _ in 0..expr.count {
                    rolls.push(systems::roll_fate(&mut self.rng));
                }
            }
        }

        // Apply keep/drop modifiers (from Story 1)
        let (kept, dropped) = self.apply_keep_drop(&rolls, &expr.modifiers);

        // Calculate modifier total
        let modifier_total = self.sum_modifiers(&expr.modifiers);

        // Calculate final total
        let total = kept.iter().sum::<i32>() + modifier_total;

        // Fate ladder if applicable
        let fate_ladder = match expr.sides {
            DiceSides::Fate => Some(systems::fate_ladder(total).to_string()),
            _ => None,
        };

        Ok(RollResult {
            expression: expr.clone(),
            rolls,
            kept,
            dropped,
            modifier_total,
            total,
            explosions,
            fate_ladder,
        })
    }
}
```

### Output Extensions (Story 2)

```rust
// src/output.rs - EXTEND format_roll()

/// Format exploding dice: "[6! → 4] = 10"
fn format_explosion(chain: &ExplosionChain) -> String {
    if chain.values.len() == 1 {
        format!("[{}]", chain.values[0])
    } else {
        let chain_str = chain.values.iter()
            .map(|v| v.to_string())
            .collect::<Vec<_>>()
            .join("! → ");
        format!("[{}] = {}", chain_str, chain.total)
    }
}

/// Format Fate dice: "[+] [-] [ ] [+]"
fn format_fate(rolls: &[i32]) -> String {
    rolls.iter()
        .map(|v| match v {
            -1 => "[-]",
            0 => "[ ]",
            1 => "[+]",
            _ => "[?]",
        })
        .collect::<Vec<_>>()
        .join(" ")
}

/// Format with Fate ladder: "+3 (Good)"
fn format_fate_total(total: i32, ladder: &str) -> String {
    let sign = if total >= 0 { "+" } else { "" };
    format!("{}{} ({})", sign, total, ladder)
}

// Updated format_roll() to handle:
// - Exploding dice chains in output
// - Fate dice symbols and ladder
```

